// ===== TEMPERATURA POR TIEMPO: FLAG POR-CUENTA temp_decay_v2 (mismo patron defensivo que repartoV2Activo) =====
// Desacopla la temperatura del status: los eventos calientes la SUBEN (via nuevaTemperaturaConDecay, que solo sube)
// y un cron aparte (revisarDecaimientoTemperatura) la BAJA sola por inactividad (caliente->tibio->frio). Con el flag
// OFF (default: false / ausente / null / columna inexistente / cualquier error) -> comportamiento ACTUAL EXACTO:
// nuevaTemperaturaConDecay devuelve la propuesta por estado tal cual, y el cron hace early-return. TRUE -> el helper
// solo sube y el cron enfria por tiempo. FAIL-SAFE: si la columna no existe, el .select devuelve error -> OFF.
// Reusa un bs ya cargado si trae la propiedad (evita una query extra por mensaje).
async function tempDecayActivo(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'temp_decay_v2')) return bs.temp_decay_v2 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('temp_decay_v2').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> comportamiento actual (flag OFF)
    return !!(data && data.temp_decay_v2 === true);
  } catch (e) { return false; } // ante cualquier fallo, NUNCA romper: tratar como flag OFF
}

// ===== OPORTUNIDADES v1: FLAG POR-CUENTA oportunidades_v1 (mismo patron defensivo que repartoV2Activo) =====
// GATE del motor de ENVIOS SEGMENTADOS ("Oportunidades"): un broadcast SEPARADO del recontacto, con su propia cola y
// su propio cupo. Con el flag OFF (default: false / ausente / null / columna inexistente / cualquier error) -> el
// cron procesarOportunidades() hace continue por cuenta y NO manda NADA, y los endpoints existen pero no disparan
// envios. TRUE -> el cron procesa la oportunidad activa de menor prioridad con goteo seguro. FAIL-SAFE: si la columna
// todavia no existe en prod (migracion-oportunidades.sql no corrida), el .select devuelve error -> tratamos como OFF.
// Reusa un bs ya cargado si trae la propiedad (evita una query extra).
async function oportunidadesV1Activo(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'oportunidades_v1')) return bs.oportunidades_v1 === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('oportunidades_v1').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> comportamiento actual (flag OFF)
    return !!(data && data.oportunidades_v1 === true);
  } catch (e) { return false; } // ante cualquier fallo, NUNCA romper: tratar como flag OFF
}

// Horas de inactividad para que un lead CALIENTE baje a TIBIO (business_settings.temp_horas_caliente_a_tibio).
// DEFAULT 48. Validado 1..8760 (fuera de rango/ausente/error -> 48). Reusa un bs ya cargado si lo trae. Ante cualquier
// error -> 48 (nunca romper). Solo se consulta cuando temp_decay_v2 esta ON.
async function tempHorasCalienteATibio(user_id, bs) {
  const _DEF = 48;
  try {
    let _raw = null;
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'temp_horas_caliente_a_tibio')) { _raw = bs.temp_horas_caliente_a_tibio; }
    else if (user_id) {
      const { data, error } = await supabase.from('business_settings').select('temp_horas_caliente_a_tibio').eq('user_id', user_id).maybeSingle();
      if (!error && data) _raw = data.temp_horas_caliente_a_tibio;
    }
    const _n = Number(_raw);
    if (_n && _n >= 1 && _n <= 8760) return _n;
    return _DEF;
  } catch (e) { return _DEF; }
}

// Horas de inactividad ADICIONALES (despues de tibio) para que un lead TIBIO baje a FRIO
// (business_settings.temp_horas_tibio_a_frio). DEFAULT 120. Validado 1..8760 (fuera de rango/ausente/error -> 120).
// CRITERIO: la inactividad se mide SIEMPRE desde la ultima actividad del lead, y el umbral tibio->frio es
// ACUMULATIVO = temp_horas_caliente_a_tibio + temp_horas_tibio_a_frio (asi la secuencia natural es
// caliente -> [48h] -> tibio -> [+120h] -> frio). Solo se consulta cuando temp_decay_v2 esta ON.
async function tempHorasTibioAFrio(user_id, bs) {
  const _DEF = 120;
  try {
    let _raw = null;
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'temp_horas_tibio_a_frio')) { _raw = bs.temp_horas_tibio_a_frio; }
    else if (user_id) {
      const { data, error } = await supabase.from('business_settings').select('temp_horas_tibio_a_frio').eq('user_id', user_id).maybeSingle();
      if (!error && data) _raw = data.temp_horas_tibio_a_frio;
    }
    const _n = Number(_raw);
    if (_n && _n >= 1 && _n <= 8760) return _n;
    return _DEF;
  } catch (e) { return _DEF; }
}

// Nivel numerico de una temperatura para comparar "cual es mas caliente": frio(0) < tibio(1) < caliente(2).
// Cualquier valor desconocido/null -> 0 (lo mas frio), asi nunca "sube" por error a algo no reconocido.
function _nivelTemperatura(t) {
  if (t === 'caliente') return 2;
  if (t === 'tibio') return 1;
  return 0; // 'frio', null, undefined o cualquier otro
}

// HELPER CENTRAL (temp-decay): decide que temperatura escribir cuando un CAMBIO DE ESTADO propone una temperatura.
//   - flagOn=false (default OFF / comportamiento ACTUAL EXACTO): devuelve la propuesta por estado TAL CUAL.
//   - flagOn=true: devuelve el MAXIMO (mas caliente) entre la actual y la propuesta -> un cambio de estado SOLO PUEDE
//     SUBIR la temperatura, nunca bajarla. El enfriamiento lo hace el cron por TIEMPO, no el cambio de estado.
// 'actual' puede venir null/undefined (conv sin temperatura previa): con flag ON eso cuenta como 0 (frio) y la
// propuesta gana; con flag OFF se ignora y se devuelve la propuesta igual. Puramente en memoria, 0 IA, 0 queries.
function nuevaTemperaturaConDecay(actual, propuestaPorEstado, flagOn) {
  if (!flagOn) return propuestaPorEstado; // OFF: byte-identico a hoy
  return _nivelTemperatura(actual) > _nivelTemperatura(propuestaPorEstado) ? actual : propuestaPorEstado;
}

// Version que RESUELVE la temperatura actual sola cuando hace falta. Pensada para los call sites donde NO tenemos
// la temperatura vigente cargada en memoria (webhook / clasificacion). Con el flag OFF (o sin user_id) hace
// early-return devolviendo la propuesta TAL CUAL, SIN ninguna query -> comportamiento ACTUAL EXACTO / byte-identico
// (cero costo por mensaje). Solo con el flag ON hace UNA query chica .select('temperatura') de esa conv y aplica el
// MAXIMO (nunca baja). Ante cualquier error de lectura -> devuelve la propuesta (fail-open al comportamiento actual).
async function _tempConDecayParaConv(convId, propuestaPorEstado, userId, bs) {
  try {
    if (!(await tempDecayActivo(userId, bs))) return propuestaPorEstado; // OFF: sin query, byte-identico a hoy
    if (!convId) return propuestaPorEstado;
    const { data, error } = await supabase.from('conversations').select('temperatura').eq('id', convId).maybeSingle();
    if (error || !data) return propuestaPorEstado; // fail-open
    return nuevaTemperaturaConDecay(data.temperatura, propuestaPorEstado, true);
  } catch (e) { return propuestaPorEstado; } // nunca romper: caer al comportamiento actual
}

// TAREA F (derivacion-v3-refinements, NO gated / aditiva): resuelve QUIEN escribio un mensaje humano a partir del
// auth_user_id autenticado (verificarUsuario) y el tenant dueno de la conv. Devuelve { asesorId, nombre }:
//   - Si el que escribe es el DUENO de la cuenta (uid === ownerId): { asesorId: null, nombre: <agent-off? nombre del
//     negocio> } -> etiquetamos como 'Dueño' (o el nombre del negocio si lo tenemos facil).
//   - Si es un ASESOR de la cuenta (fila en asesores con auth_user_id=uid, admin_id=ownerId): { asesorId, nombre }.
//   - Ante cualquier error / no encontrado: { asesorId: null, nombre: null } (los inserts caen a su default).
// 0 tokens. Nunca tira (best-effort): la atribucion es cosmetica, no debe romper el envio.
async function _resolverAutorMensaje(ownerId, uid) {
  try {
    if (!uid) return { asesorId: null, nombre: null };
    if (ownerId && uid === ownerId) {
      // El dueno escribiendo desde la app. Intentar un nombre lindo (business_settings.company_name) sin romper.
      let _nom = 'Dueño';
      try {
        const { data: _bs } = await supabase.from('business_settings').select('company_name').eq('user_id', ownerId).maybeSingle();
        if (_bs && _bs.company_name && String(_bs.company_name).trim()) _nom = String(_bs.company_name).trim();
      } catch (eN) {}
      return { asesorId: null, nombre: _nom };
    }
    const { data: _ase } = await supabase.from('asesores').select('id, nombre').eq('auth_user_id', uid).eq('admin_id', ownerId).maybeSingle();
    if (_ase && _ase.id) return { asesorId: _ase.id, nombre: (_ase.nombre && String(_ase.nombre).trim()) ? String(_ase.nombre).trim() : null };
    return { asesorId: null, nombre: null };
  } catch (e) { return { asesorId: null, nombre: null }; }
}

// TAREA F (derivacion-v3-refinements, NO gated / aditiva / DEFENSIVA): inserta un mensaje agregando la atribucion de
// autor (autor_asesor_id, autor_nombre) SIN romper si esas columnas todavia no existen en prod. Patron reintento-sin-
// columna (como otros inserts del codigo): primero intenta con los campos de autor; si PostgREST rechaza por columna
// inexistente (PGRST204 u otro), reintenta con el payload base (sin los campos de autor). Devuelve el resultado del
// insert (con .select(...) si se pide via opts.select). NO gated: aplica siempre. 0 tokens.
async function _insertMensajeConAutor(baseRow, autor, opts) {
  opts = opts || {};
  const _selCols = opts.select || null;
  const _single = opts.single === true; // true -> .single(); default -> .maybeSingle() cuando hay select
  const _autorRow = Object.assign({}, baseRow, {
    autor_asesor_id: (autor && autor.asesorId) ? autor.asesorId : null,
    autor_nombre: (autor && autor.nombre) ? autor.nombre : null
  });
  async function _run(row) {
    let q = supabase.from('messages').insert(row);
    if (_selCols) { q = q.select(_selCols); q = _single ? q.single() : q.maybeSingle(); }
    return await q;
  }
  // El reintento sin columnas de autor SOLO debe dispararse cuando el error es por columna inexistente (migracion no
  // corrida): PGRST204, o el mensaje menciona autor_asesor_id/autor_nombre / "column". Para CUALQUIER otro error
  // (ej. FK, RLS) NO reintentamos -> evita el riesgo de insert DUPLICADO (el primer insert que falla por columna NO
  // escribe nada, asi que el reintento es seguro; pero un error no-columna podria haber escrito y duplicariamos).
  function _esErrorDeColumna(err) {
    if (!err) return false;
    const _code = err.code || '';
    const _msg = String(err.message || err.details || err.hint || '').toLowerCase();
    return _code === 'PGRST204'
      || _msg.indexOf('autor_asesor_id') >= 0
      || _msg.indexOf('autor_nombre') >= 0
      || (_msg.indexOf('column') >= 0 && (_msg.indexOf('does not exist') >= 0 || _msg.indexOf('schema cache') >= 0 || _msg.indexOf('could not find') >= 0));
  }
  let _rowErr = null;
  try {
    const r = await _run(_autorRow);
    if (r && r.error) { _rowErr = r.error; } else { return r; } // sin error -> listo
  } catch (eAutor) { _rowErr = eAutor; }
  // Hubo error con las columnas de autor. Reintentar SIN ellas SOLO si es error de columna; si no, devolver el error.
  if (_esErrorDeColumna(_rowErr)) {
    try { return await _run(baseRow); } catch (eBase) { return { data: null, error: eBase }; }
  }
  return { data: null, error: _rowErr };
}

// ===== FLAG POR-CUENTA consulta_dueno_activa (DESACOPLA el ciclo de aprendizaje de reparto_v2) =====
// Mismo patron defensivo que repartoV2Activo. DEFAULT OFF: false / null / ausente / columna inexistente ->
// false (comportamiento ACTUAL EXACTO). Habilita el ciclo "consultar_al_dueno" (tool + relay de respuesta al
// lead + variante fuera-de-horario) SIN necesidad de encender reparto_v2. Ante cualquier error -> false.
async function consultaDuenoActiva(user_id, bs) {
  try {
    if (bs && Object.prototype.hasOwnProperty.call(bs, 'consulta_dueno_activa')) return bs.consulta_dueno_activa === true;
    if (!user_id) return false;
    const { data, error } = await supabase.from('business_settings').select('consulta_dueno_activa').eq('user_id', user_id).maybeSingle();
    if (error) return false; // columna ausente u otro error -> flag OFF (actual)
    return !!(data && data.consulta_dueno_activa === true);
  } catch (e) { return false; }
}

// GATE UNICO del ciclo de aprendizaje/consulta-al-dueno: (consulta_dueno_activa OR reparto_v2). Con AMBOS OFF
// devuelve false => NADA del ciclo corre (comportamiento ACTUAL EXACTO). Reusa un bs ya cargado si lo trae
// (evita queries extra). Ante cualquier error -> false (NUNCA romper).
async function cicloAprendizajeActivo(user_id, bs) {
  try {
    if (await consultaDuenoActiva(user_id, bs)) return true;
    return await repartoV2Activo(user_id, bs);
  } catch (e) { return false; }
}

