        const _qt = _qm.conversation
          || (_qm.extendedTextMessage && _qm.extendedTextMessage.text)
          || (_qm.imageMessage && _qm.imageMessage.caption)
          || (_qm.videoMessage && _qm.videoMessage.caption)
          || '';
