// ===== MOTOR DE SCRAPING AUTOMATICO (revisa cada hora que cuentas deben actualizar inventario) =====
async function correrScrapingDeUsuario(cfg) {
  // trae propiedades de la fuente y las guarda en modo directo (upsert por numero)
  try {
    var sitio = (cfg.fuente_url || '').trim();
    if (!sitio) return { ok: false, motivo: 'sin url' };
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    var lista = await traerListaPropiedades(sitio, null);
    if (!lista.length) return { ok: false, motivo: 'sin propiedades' };
    var creados = 0, actualizados = 0, errores = 0;
    var numerosVistos = {}; // numeros que SÍ figuran en el sitio en esta corrida
    // DEPLOY-SAFE: si la columna pausa_manual aun NO existe (migracion no corrida), caemos al comportamiento
    // anterior (sin auto-pausa/despausa) para no romper la actualizacion de inventario. Al existir, se activa sola.
    var _tienePausa = true;
    try { var _pb = await supabase.from('properties').select('pausa_manual').limit(1); if (_pb.error) _tienePausa = false; } catch (e) { _tienePausa = false; }
    var _selCols = _tienePausa ? 'id, images, pausa_manual' : 'id, images';
    for (var i = 0; i < lista.length; i++) {
      try {
        var p = await procesarPropiedad(lista[i]);
        if (!p.numero) { errores++; continue; }
        numerosVistos[String(p.numero)] = 1;
        var fila = {
          user_id: cfg.user_id, numero: String(p.numero), title: p.titulo || 'Sin titulo',
          type: p.tipo || null, zone: [p.ciudad, p.zona].filter(Boolean).join(' - ') || null,
          price: p.precio || null, description: p.descripcion || null,
          caracteristicas: p.caracteristicas || null, link: p.link || null
        };
        var _fotos = Array.isArray(p.fotos) ? p.fotos : [];
        var ex = await supabase.from('properties').select(_selCols).eq('user_id', cfg.user_id).eq('numero', String(p.numero)).maybeSingle();
        if (ex.data && ex.data.id) {
          // FIGURA en el sitio -> auto-DESPAUSA (activa=true) y actualiza info, SALVO que la hayas pausado a mano
          // (pausa_manual): en ese caso se respeta tu pausa (activa=false) pero igual se refresca la info.
          fila.activa = (_tienePausa && ex.data.pausa_manual) ? false : true;
          // Refrescar fotos SOLO si la galeria guardada es POBRE (<2): rellena las de 0-1 foto sin pisar
          // galerias buenas ni las fotos ya CLASIFICADAS (categoria) de las propiedades sanas.
          var _stored = Array.isArray(ex.data.images) ? ex.data.images.length : 0;
          if (_stored < 2 && _fotos.length > _stored) fila.images = _fotos.map(function(u){ return { url: u }; });
          var up = await supabase.from('properties').update(fila).eq('id', ex.data.id);
          if (up.error) errores++; else actualizados++;
        } else {
          fila.activa = true;
          if (_fotos.length) fila.images = _fotos.map(function(u){ return { url: u }; });
          var ins = await supabase.from('properties').insert(fila);
          if (ins.error) errores++; else creados++;
        }
      } catch (e) { errores++; }
    }
    // AUTO-PAUSA de las que YA NO figuran en el sitio: activa=false (NO se borran, quedan en el inventario). Nunca
    // toca las pausadas a mano (pausa_manual). SALVAGUARDA anti-scrape-parcial: solo se auto-pausa si la corrida
    // cubrio la mayor parte del catalogo scrapeado (>=70%); si el sitio vino corto (caida), no se pausa nada.
    var pausadas = 0;
    if (_tienePausa) try {
      var vistos = Object.keys(numerosVistos);
      var todasR = await supabase.from('properties').select('id, numero, pausa_manual, link, activa').eq('user_id', cfg.user_id);
      var todas = (todasR.data || []).filter(function(x){ return x.link; }); // solo las de origen scraping (tienen link)
      var baseScrapeadas = todas.filter(function(x){ return !x.pausa_manual; }).length || 1;
      var cobertura = vistos.length / baseScrapeadas;
      var candidatas = todas.filter(function(x){ return x.activa !== false && !x.pausa_manual && !numerosVistos[String(x.numero)]; });
      if (cobertura >= 0.7 && candidatas.length) {
        var ids = candidatas.map(function(x){ return x.id; });
        for (var j = 0; j < ids.length; j += 200) {
          var loteIds = ids.slice(j, j + 200);
          var upP = await supabase.from('properties').update({ activa: false }).in('id', loteIds);
          if (!upP.error) pausadas += loteIds.length;
        }
      }
    } catch (e) {}
    return { ok: true, creados: creados, actualizados: actualizados, pausadas: pausadas, errores: errores, total: lista.length };
  } catch (e) { return { ok: false, motivo: e && e.message }; }
}

// Endpoint para correr el scraping automatico de una cuenta a pedido (sirve para probar el motor)
app.post('/api/scraping-config/correr-ahora', async function(req, res) {
  try {
    var user_id = await verificarUsuario(req);
    if (!user_id) return res.status(401).json({ error: 'No autorizado' });
    var q = await supabase.from('scraping_config').select('*').eq('user_id', user_id).maybeSingle();
    if (!q.data) return res.json({ ok: false, mensaje: 'No hay configuracion guardada' });
    // Un scrape completo puede tardar varios minutos (baja la lista + ficha + galeria por propiedad).
    // Respondemos YA y corremos en segundo plano: evita que el request HTTP quede colgado / lo corte el proxy.
    // El frontend ya muestra "se esta ejecutando en segundo plano" y no espera este resultado.
    res.json({ ok: true, corriendo: true, mensaje: 'La actualizacion se esta ejecutando en segundo plano.' });
    (async function () {
      try {
        var r = (q.data.modo === 'directo') ? await correrScrapingDeUsuario(q.data) : await correrScrapingPendiente(q.data);
        await supabase.from('scraping_config').update({ ultimo_scraping: new Date().toISOString() }).eq('user_id', user_id);
        console.log('[correr-ahora] user', user_id, 'resultado', JSON.stringify(r));
      } catch (e) { console.error('[correr-ahora bg]', e && e.message); }
    })();
  } catch (e) { try { return res.status(500).json({ error: e && e.message }); } catch (e2) {} }
});

async function correrScrapingPendiente(cfg) {
  // compara lo scrapeado con la base y guarda diferencias en scraping_pendientes (no aplica)
  try {
    var sitio = (cfg.fuente_url || '').trim();
    if (!sitio) return { ok: false, motivo: 'sin url' };
    if (!sitio.startsWith('http')) sitio = 'https://' + sitio;
    var lista = await traerListaPropiedades(sitio, null);
    if (!lista.length) return { ok: false, motivo: 'sin propiedades' };
    // limpiar pendientes anteriores de este usuario (se reemplazan por el scraping nuevo)
    await supabase.from('scraping_pendientes').delete().eq('user_id', cfg.user_id);
    var nuevas = 0, modificadas = 0;
    for (var i = 0; i < lista.length; i++) {
      try {
        var p = await procesarPropiedad(lista[i]);
        if (!p.numero) continue;
        var _fotosPend = Array.isArray(p.fotos) ? p.fotos : [];
        var nuevo = {
          numero: String(p.numero), title: p.titulo || 'Sin titulo', type: p.tipo || null,
          zone: [p.ciudad, p.zona].filter(Boolean).join(' - ') || null, price: p.precio || null,
          description: p.descripcion || null, caracteristicas: p.caracteristicas || null, link: p.link || null,
          images: _fotosPend.length ? _fotosPend.map(function(u){ return { url: u }; }) : null
        };
        var ex = await supabase.from('properties').select('id,title,price,zone,description,images').eq('user_id', cfg.user_id).eq('numero', String(p.numero)).maybeSingle();
        if (ex.data && ex.data.id) {
          // existe: detectar si cambio algo relevante (precio, titulo, zona, descripcion) o si la web tiene MAS fotos que las guardadas
          var v = ex.data;
          var _storedN = Array.isArray(v.images) ? v.images.length : 0;
          var _masFotos = _storedN < 2 && _fotosPend.length > _storedN; // solo si la galeria guardada es pobre
          var cambio = _masFotos || (String(v.price||'') !== String(nuevo.price||'')) || (String(v.title||'') !== String(nuevo.title||'')) || (String(v.zone||'') !== String(nuevo.zone||'')) || (String(v.description||'') !== String(nuevo.description||''));
          if (cambio) {
            await supabase.from('scraping_pendientes').insert({ user_id: cfg.user_id, numero: String(p.numero), tipo_cambio: 'modificada', titulo: nuevo.title, datos_nuevos: nuevo, datos_viejos: { title: v.title, price: v.price, zone: v.zone }, property_id: v.id });
            modificadas++;
          }
        } else {
          // no existe: es nueva
          await supabase.from('scraping_pendientes').insert({ user_id: cfg.user_id, numero: String(p.numero), tipo_cambio: 'nueva', titulo: nuevo.title, datos_nuevos: nuevo, datos_viejos: null, property_id: null });
          nuevas++;
        }
      } catch (e) {}
    }
    return { ok: true, nuevas: nuevas, modificadas: modificadas, total: lista.length };
  } catch (e) { return { ok: false, motivo: e && e.message }; }
}
async function revisarScrapingsAutomaticos() {
  try {
    var q = await supabase.from('scraping_config').select('*').eq('automatico', true);
    var cuentas = q.data || [];
    if (!cuentas.length) return;
    var ahora = new Date();
    var hoyStr = ahora.toISOString().substring(0, 10);
    var diaSemana = ahora.getDay();
    var diaMes = ahora.getDate();
    var horaActual = ahora.getHours();
    var nombresDias = ['dom','lun','mar','mie','jue','vie','sab'];
    var diaHoy = nombresDias[diaSemana];
    for (var i = 0; i < cuentas.length; i++) {
      var cfg = cuentas[i];
      // GUARD POR RUBRO: este cron scrapea PROPERTIES (listados de inmobiliaria). Hotel no scrapea propiedades y
      // desarrolladora tiene su propio cron (revisarScrapingsDesarrollo). Si la cuenta no es inmobiliaria, saltar
      // (evita filas huerfanas en properties que la IA de ese rubro ignora). Defensivo: ante error, no bloquea.
      try {
        var _bsRubro = await supabase.from('business_settings').select('rubro').eq('user_id', cfg.user_id).maybeSingle();
        if (normalizarRubro((_bsRubro.data && _bsRubro.data.rubro) || 'inmobiliaria') !== 'inmobiliaria') continue;
      } catch (eGuardR) {}
      var horarios = Array.isArray(cfg.horarios) ? cfg.horarios : [];
      var dias = Array.isArray(cfg.dias_semana) ? cfg.dias_semana : [];
      // determinar la hora objetivo segun frecuencia
      var horasObjetivo = horarios.map(function(h){ return parseInt(String(h).split(':')[0], 10); }).filter(function(n){ return !isNaN(n); });
      if (!horasObjetivo.length) horasObjetivo = [9];
      var leToca = false;
      // marca anti-repeticion: para dos_por_dia usamos fecha+hora; para el resto, fecha
      var marca = hoyStr;
      if (cfg.frecuencia === 'dos_por_dia') {
        if (horasObjetivo.indexOf(horaActual) >= 0) { leToca = true; marca = hoyStr + '-' + horaActual; }
      } else if (cfg.frecuencia === 'dias_semana') {
        if (dias.indexOf(diaHoy) >= 0 && horaActual === horasObjetivo[0]) leToca = true;
      } else if (cfg.frecuencia === 'semanal') {
        if (diaSemana === 1 && horaActual === horasObjetivo[0]) leToca = true;
      } else if (cfg.frecuencia === 'mensual') {
        if (diaMes === 1 && horaActual === horasObjetivo[0]) leToca = true;
      }
      if (!leToca) continue;
      // anti-repeticion: si ya corrio con esta marca, saltar
      if (cfg.ultimo_scraping && String(cfg.ultimo_scraping).indexOf(marca) >= 0) continue;
      // correr el scraping (modo directo en esta version)
      if (cfg.modo === 'directo') {
        await correrScrapingDeUsuario(cfg);
      } else {
        await correrScrapingPendiente(cfg);
      }
      // registrar que corrio (guarda la marca para no repetir)
      await supabase.from('scraping_config').update({ ultimo_scraping: ahora.toISOString().substring(0,13) + ':00:00 marca=' + marca }).eq('user_id', cfg.user_id);
    }
  } catch (e) {}
}
// revisar cada hora, con un arranque inicial a los 90 segundos del deploy
setInterval(revisarScrapingsAutomaticos, 60 * 60 * 1000);
setTimeout(revisarScrapingsAutomaticos, 90 * 1000);


